import{_ as n,C as o,o as l,c as s,E as a,w as r,a as t,a0 as c}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Romania Legal Rights","description":"Legal rights for transgender people in Romania","frontmatter":{"layout":"doc","title":"Romania Legal Rights","description":"Legal rights for transgender people in Romania"},"headers":[],"relativePath":"europe/romania/legal-rights.md","filePath":"europe/romania/legal-rights.md","lastUpdated":null}'),d={name:"europe/romania/legal-rights.md"};function u(g,e,h,m,p,f){const i=o("Badge");return l(),s("div",null,[a(i,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[t("Medicalized Recognition",-1)])]),_:1}),a(i,{variant:"red"},{default:r(()=>[...e[1]||(e[1]=[t("Requires Court Approval",-1)])]),_:1}),a(i,{variant:"yellow"},{default:r(()=>[...e[2]||(e[2]=[t("Anti-Discrimination Framework",-1)])]),_:1}),e[3]||(e[3]=c('<h1 id="legal-rights-in-romania" tabindex="-1">Legal Rights in Romania <a class="header-anchor" href="#legal-rights-in-romania" aria-label="Permalink to &quot;Legal Rights in Romania&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Romania has a <strong>medicalized gender recognition system</strong> that functions but requires navigating multiple hurdles:</p><ul><li><strong>Requirements</strong>: Psychiatric diagnosis + documented HRT + court decision</li><li><strong>Process</strong>: File a court case after obtaining medical certification</li><li><strong>Surgery</strong>: Not explicitly required by law, though some judges may inquire</li><li><strong>Age</strong>: 18+ only</li><li><strong>Timeline</strong>: Typically 6-18 months from diagnosis to final court decision</li></ul><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li>Diagnosis from a psychiatrist or endocrinologist (Institutul de Endocrinologie in Bucharest)</li><li>Minimum 6-12 months of documented HRT</li><li>File a court case in your local tribunal</li><li>Medical expert testimony may be required</li><li>Court issues decision on gender marker change</li><li>Update civil registry and obtain new documents</li></ol><p><strong>Note</strong>: While the process is recognized, it is invasive, medicalizing, and varies by court in different counties. Courts in Bucharest, Cluj, and Timișoara are generally more favorable.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Processed through the <strong>Civil Registry</strong> (Starea Civilă)</li><li>Can be done before gender marker change</li><li>Requires justification — gender transition is accepted</li><li>Processed within 30-60 days</li><li>Some registrars may require additional documentation</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: Prohibited under the Labour Code</li><li><strong>Goods and Services</strong>: Protected under Government Ordinance 137/2000 on combating discrimination</li><li><strong>Education</strong>: General protections apply</li><li><strong>Healthcare</strong>: Access to medical services protected</li></ul><p>Romania&#39;s anti-discrimination framework is relatively comprehensive on paper, covering gender identity explicitly in some interpretations of the law. The <strong>National Council for Combating Discrimination</strong> (CNCD) handles complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> includes hate crime provisions</li><li>Sexual orientation is a protected characteristic</li><li>Gender identity is <strong>not explicitly included</strong> but may be covered by extension</li><li>Enforcement is inconsistent — police training on LGBTQ+ issues is limited</li><li>Far-right groups are active, particularly in rural areas</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards are recognized internationally</li><li>Romanian IDs (CI) and passports can be updated after court decision</li><li>Previous documents are archived</li><li>Some trans people report difficulties with authorities who are unaware of the procedures</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://acceptromania.ro/" target="_blank" rel="noreferrer">ACCEPT (LGBTQ+ Organization)</a></li><li><a href="https://www.cncd.ro/" target="_blank" rel="noreferrer">National Council for Combating Discrimination (CNCD)</a></li><li><a href="https://www.ilga-europe.org/country/romania/" target="_blank" rel="noreferrer">ILGA-Europe - Romania</a></li><li><a href="https://www.endocrinobucuresti.ro/" target="_blank" rel="noreferrer">Institutul de Endocrinologie &quot;C.I. Parhon&quot;</a></li></ul>',18))])}const C=n(d,[["render",u]]);export{y as __pageData,C as default};
